# Simulated auth tokens mapping to user IDs
AUTH_TOKENS = {
    "token-alice": "1",
    "token-bob": "2",
    "token-charlie": "3",
}


# Authentication middleware
class AuthenticationMiddleware(BaseHTTPMiddleware):
    async def dispatch(self, request: Request, call_next):
        # Extract token from Authorization header
        auth_header = request.headers.get("Authorization", "")
        current_user = None

        if auth_header.startswith("Bearer "):
            token = auth_header[7:]
            user_id = AUTH_TOKENS.get(token)
            if user_id:
                current_user = USERS.get(user_id)

        # Set current_user on request state
        request.state.current_user = current_user

        response = await call_next(request)
        return response


def get_context_value(request):
    """Build context for GraphQL resolvers from the request."""
    return {
        "request": request,
        "current_user": getattr(request.state, "current_user", None),
    }


# Query resolvers
query = QueryType()


@query.field("me")
def resolve_me(_, info):
    """Return the currently authenticated user."""
    current_user = info.context.get("current_user")
    if not current_user:
        return None
    return current_user


@query.field("user")
def resolve_user(_, info, id):
    """Fetch a user by ID."""
    return USERS.get(id)


@query.field("users")
def resolve_users(_, info):
    """Fetch all users."""
    return list(USERS.values())


@query.field("post")
def resolve_post(_, info, id):
    """Fetch a post by ID."""
    return POSTS.get(id)


@query.field("posts")
def resolve_posts(_, info):
    """Fetch all published posts."""
    return [post for post in POSTS.values() if post["published"]]


# User type resolvers
user_type = ObjectType("User")


@user_type.field("posts")
def resolve_user_posts(user, info):
    """Resolve posts belonging to a user."""
    user_id = user["id"]
    return [post for post in POSTS.values() if post["author_id"] == user_id]


@user_type.field("email")
def resolve_user_email(user, info):
    """Resolve user email - returns the email field."""
    return user.get("email")


@user_type.field("phone")
def resolve_user_phone(user, info):
    """Resolve user phone - returns the phone field."""
    return user.get("phone")


@user_type.field("address")
def resolve_user_address(user, info):
    """Resolve user address - returns the address field."""
    return user.get("address")


# Post type resolvers
post_type = ObjectType("Post")


@post_type.field("author")
def resolve_post_author(post, info):
    """Resolve the author of a post."""
    author_id = post.get("author_id")
    return USERS.get(author_id)


# Create executable schema
schema = make_executable_schema(
    type_defs, query, user_type, post_type, snake_case_fallback_resolvers
)

# Create the GraphQL ASGI app
graphql_app = GraphQL(
    schema,
    debug=True,
    context_value=get_context_value,
)

# Create Starlette app with authentication middleware
app = Starlette(
    debug=True,
    middleware=[Middleware(AuthenticationMiddleware)],
    routes=[
        Route("/graphql", graphql_app, methods=["GET", "POST"]),
    ],
)


if __name__ == "__main__":
    print("Starting GraphQL API server...")
    print("GraphQL Playground available at: http://localhost:8000/graphql")
    print()
